import React from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import Card from "../components/Card";
function Home() {
  return (
    <div>
      <div>
        <Navbar />
      </div>

      <div>
        <Card />
      </div>
      
      <div>
        <Footer />
      </div>
    </div>
  );
}

export default Home;
